"""Groq LPU streaming chat with OpenAI fallback + latency telemetry."""
import os, time, logging
from groq import Groq, APIError as GroqError
from openai import OpenAI

groq_client = Groq(api_key=os.environ['GROQ_API_KEY'])
openai_client = OpenAI()  # fallback
log = logging.getLogger(__name__)

GROQ_MODEL = 'llama-3.3-70b-versatile'
FALLBACK_MODEL = 'gpt-4o-mini'

def stream_chat(messages: list[dict], max_tokens: int = 500) -> dict:
    """Stream a chat response. Returns dict with text + telemetry."""
    start = time.time()
    ttft = None
    chunks = []
    provider = 'groq'
    try:
        stream = groq_client.chat.completions.create(
            model=GROQ_MODEL, messages=messages, stream=True, max_tokens=max_tokens,
        )
        for chunk in stream:
            if chunk.choices[0].delta.content:
                if ttft is None:
                    ttft = (time.time() - start) * 1000
                chunks.append(chunk.choices[0].delta.content)
    except GroqError as e:
        log.warning('Groq error, falling back to OpenAI: %s', e)
        provider = f'openai-fallback (groq: {type(e).__name__})'
        ttft = chunks = None  # reset for fallback
        start = time.time(); chunks = []; ttft = None
        stream = openai_client.chat.completions.create(
            model=FALLBACK_MODEL, messages=messages, stream=True, max_tokens=max_tokens,
        )
        for chunk in stream:
            if chunk.choices[0].delta.content:
                if ttft is None:
                    ttft = (time.time() - start) * 1000
                chunks.append(chunk.choices[0].delta.content)
    end = time.time()
    text = ''.join(chunks)
    return {
        'text': text,
        'provider': provider,
        'ttft_ms': round(ttft or 0, 1),
        'total_ms': round((end - start) * 1000, 1),
        'tokens_estimated': len(text.split()) * 1.3,
    }

if __name__ == '__main__':
    result = stream_chat([{'role': 'user', 'content': 'Explain LPU vs GPU in one paragraph.'}])
    print(f"provider={result['provider']} ttft={result['ttft_ms']}ms total={result['total_ms']}ms")
    print(result['text'])

