# agent.py — Claude 4 streaming agent with parallel tool calls
import json
import os
from typing import Any

from anthropic import Anthropic

client = Anthropic()

# Tool definitions — JSON Schema matching Anthropic's spec
TOOLS = [
    {
        'name': 'search_docs',
        'description': 'Search the internal documentation. Returns top 5 matching passages.',
        'input_schema': {
            'type': 'object',
            'properties': {
                'query': {'type': 'string', 'description': 'natural-language query'},
                'limit': {'type': 'integer', 'default': 5, 'minimum': 1, 'maximum': 20},
            },
            'required': ['query'],
        },
    },
    {
        'name': 'get_weather',
        'description': 'Get current weather for a city.',
        'input_schema': {
            'type': 'object',
            'properties': {'city': {'type': 'string'}},
            'required': ['city'],
        },
    },
]


def execute_tool(name: str, args: dict[str, Any]) -> str:
    """Dispatch to your real tool implementations. Return string result."""
    if name == 'search_docs':
        # stub — replace with real retriever
        return json.dumps({'results': [f"doc{i}: matches '{args['query']}'" for i in range(args.get('limit', 3))]})
    if name == 'get_weather':
        return json.dumps({'city': args['city'], 'temp_c': 22, 'cond': 'partly cloudy'})
    return json.dumps({'error': f'unknown tool {name}'})


def run_agent(user_message: str, max_iterations: int = 5):
    """Run the agent loop until Claude returns end_turn (no more tool calls)."""
    messages = [{'role': 'user', 'content': user_message}]

    for iteration in range(max_iterations):
        print(f'\n=== iteration {iteration + 1} ===\n')

        # Streaming with tool use — accumulate text + capture tool_use blocks
        with client.messages.stream(
            model='claude-sonnet-4-5-20250929',
            max_tokens=4096,
            tools=TOOLS,
            messages=messages,
        ) as stream:
            for text in stream.text_stream:
                print(text, end='', flush=True)
            final = stream.get_final_message()

        # Was this end_turn? Then we're done.
        if final.stop_reason == 'end_turn':
            messages.append({'role': 'assistant', 'content': final.content})
            return final

        # Was this tool_use? Execute all tool_use blocks in parallel-conceptually
        # (Anthropic emits multiple tool_use blocks per turn; execute them all,
        # then return all results in a single user turn)
        if final.stop_reason == 'tool_use':
            messages.append({'role': 'assistant', 'content': final.content})
            tool_results = []
            for block in final.content:
                if block.type == 'tool_use':
                    print(f'\n→ executing {block.name}({block.input})')
                    result = execute_tool(block.name, block.input)
                    tool_results.append({
                        'type': 'tool_result',
                        'tool_use_id': block.id,
                        'content': result,
                    })
            messages.append({'role': 'user', 'content': tool_results})
            continue

        # Other stop_reason — max_tokens, etc.
        print(f'\n[stopped: {final.stop_reason}]')
        return final

    raise RuntimeError(f'agent did not converge after {max_iterations} iterations')


if __name__ == '__main__':
    run_agent('What is the weather in Tokyo and Paris, and find me our docs about RAG?')

