"""smolagents CodeAgent with web search + Python execution."""
from __future__ import annotations

import os

from smolagents import CodeAgent, DuckDuckGoSearchTool, LiteLLMModel, tool


@tool
def get_current_time() -> str:
    """Get the current UTC datetime as ISO string."""
    from datetime import datetime, timezone
    return datetime.now(timezone.utc).isoformat()


@tool
def calculate(expression: str) -> str:
    """Evaluate a Python math expression. Returns string result. Example: '2 + 2 * 3' -> '8'.

    Args:
        expression: A Python expression to evaluate. NO imports, no calls.
    """
    import math
    allowed = {"__builtins__": {}, "abs": abs, "round": round, "min": min, "max": max, "pow": pow, "math": math}
    try:
        return str(eval(expression, allowed))
    except Exception as e:
        return f"ERROR: {e}"


def build():
    model = LiteLLMModel(model_id="anthropic/claude-sonnet-4-5", api_key=os.environ["ANTHROPIC_API_KEY"])
    return CodeAgent(
        tools=[DuckDuckGoSearchTool(), get_current_time, calculate],
        model=model,
        additional_authorized_imports=["math", "datetime", "json"],
        max_steps=8,
    )


if __name__ == "__main__":
    import sys
    task = sys.argv[1] if len(sys.argv) > 1 else "How many days until 2027? Also fetch today's top OSS LLM news."
    agent = build()
    result = agent.run(task)
    print(result)

