/**
 * MCP filesystem server - sandboxed to a single root.
 *
 * Usage: npx tsx fs-server.ts /allowed/root [--max-bytes 1048576]
 */
import { Server } from "@modelcontextprotocol/sdk/server/index.js";
import { StdioServerTransport } from "@modelcontextprotocol/sdk/server/stdio.js";
import { CallToolRequestSchema, ListToolsRequestSchema } from "@modelcontextprotocol/sdk/types.js";
import fs from "node:fs/promises";
import path from "node:path";

const ROOT = path.resolve(process.argv[2] ?? process.cwd());
const MAX_BYTES = Number(process.env.MCP_MAX_BYTES ?? 1_048_576); // 1 MiB

async function safeJoin(rel: string): Promise<string> {
  const joined = path.resolve(ROOT, rel);
  const real = await fs.realpath(joined).catch(() => joined);
  if (!real.startsWith(ROOT + path.sep) && real !== ROOT) {
    throw new Error(`Path escapes sandbox: ${rel}`);
  }
  return real;
