const server = new Server({ name: "filesystem", version: "1.0.0" }, { capabilities: { tools: {} } });

server.setRequestHandler(ListToolsRequestSchema, async () => ({
  tools: [
    {
      name: "list_directory",
      description: "List files + subdirs (relative path).",
      inputSchema: { type: "object", properties: { path: { type: "string", default: "." } } },
    },
    {
      name: "read_file",
      description: "Read text file (UTF-8, max 1 MiB).",
      inputSchema: { type: "object", required: ["path"], properties: { path: { type: "string" } } },
    },
    {
      name: "write_file",
      description: "Write text file (UTF-8, max 1 MiB). Creates parent dirs.",
      inputSchema: {
        type: "object",
        required: ["path", "content"],
        properties: { path: { type: "string" }, content: { type: "string" } },
      },
    },
  ],
}));

server.setRequestHandler(CallToolRequestSchema, async (req) => {
  const { name, arguments: args } = req.params;
  try {
    if (name === "list_directory") {
      const target = await safeJoin((args?.path as string) ?? ".");
      const entries = await fs.readdir(target, { withFileTypes: true });
      return { content: [{ type: "text", text: JSON.stringify(entries.map((e) => ({ name: e.name, type: e.isDirectory() ? "dir" : "file" }))) }] };
    }
    if (name === "read_file") {
      const target = await safeJoin(args!.path as string);
      const stat = await fs.stat(target);
      if (stat.size > MAX_BYTES) throw new Error(`File too large: ${stat.size} > ${MAX_BYTES}`);
      const text = await fs.readFile(target, "utf-8");
      return { content: [{ type: "text", text }] };
    }
    if (name === "write_file") {
      const content = args!.content as string;
      if (Buffer.byteLength(content, "utf-8") > MAX_BYTES) throw new Error(`Payload too large > ${MAX_BYTES}`);
      const target = await safeJoin(args!.path as string);
      await fs.mkdir(path.dirname(target), { recursive: true });
      await fs.writeFile(target, content, "utf-8");
      return { content: [{ type: "text", text: `wrote ${Buffer.byteLength(content)} bytes` }] };
    }
    throw new Error(`Unknown tool: ${name}`);
  } catch (err) {
    return { content: [{ type: "text", text: `ERROR: ${(err as Error).message}` }], isError: true };
  }
});

const transport = new StdioServerTransport();
