"""OpenAI strict JSON via response_format + Pydantic."""
from __future__ import annotations

import os
from openai import OpenAI
from pydantic import BaseModel, Field
from typing import Literal


class CalendarEvent(BaseModel):
    name: str
    date: str = Field(description="ISO 8601 date YYYY-MM-DD")
    participants: list[str]
    location: Literal["zoom", "office", "external"]


client = OpenAI()


def extract_event(text: str) -> CalendarEvent:
    """Use the typed .parse() helper - returns a validated Pydantic model directly."""
    completion = client.chat.completions.parse(
        model="gpt-5",                    # or "gpt-4o-2024-08-06" or later
        messages=[
            {"role": "system", "content": "Extract event details. Reply with the parsed event ONLY."},
            {"role": "user", "content": text},
        ],
        response_format=CalendarEvent,
    )
    return completion.choices[0].message.parsed   # already a CalendarEvent instance


# Alternative: raw json_schema mode if you don't use Pydantic
def extract_event_raw(text: str) -> dict:
    SCHEMA = {
        "type": "json_schema",
        "json_schema": {
            "name": "calendar_event",
            "strict": True,
            "schema": {
                "type": "object",
                "properties": {
                    "name": {"type": "string"},
                    "date": {"type": "string"},
                    "participants": {"type": "array", "items": {"type": "string"}},
                    "location": {"type": "string", "enum": ["zoom", "office", "external"]},
                },
                "required": ["name", "date", "participants", "location"],
                "additionalProperties": False,
            },
        },
    }
    resp = client.chat.completions.create(
        model="gpt-5",
        messages=[
            {"role": "system", "content": "Extract event details."},
            {"role": "user", "content": text},
        ],
        response_format=SCHEMA,
    )
    import json
    return json.loads(resp.choices[0].message.content)


