"""Claude 4 parallel tool use with asyncio.gather."""
from __future__ import annotations

import asyncio
import json
import os
from typing import Any

from anthropic import AsyncAnthropic


TOOLS = [
    {
        "name": "get_weather",
        "description": "Return current weather for a city.",
        "input_schema": {
            "type": "object",
            "required": ["city"],
            "properties": {"city": {"type": "string"}, "unit": {"type": "string", "enum": ["celsius", "fahrenheit"], "default": "celsius"}},
        },
    },
    {
        "name": "get_time",
        "description": "Return current local time in a city.",
        "input_schema": {
            "type": "object",
            "required": ["city"],
            "properties": {"city": {"type": "string"}},
        },
    },
]


# --- Tool implementations (your real code goes here) ---
async def get_weather(city: str, unit: str = "celsius") -> dict:
    await asyncio.sleep(0.5)  # simulate API call
    return {"city": city, "temp": 18, "condition": "cloudy", "unit": unit}


async def get_time(city: str) -> dict:
    await asyncio.sleep(0.3)
    return {"city": city, "time": "14:23:00", "timezone": "UTC+1"}


TOOL_FUNCS = {"get_weather": get_weather, "get_time": get_time}


async def execute_tool(block) -> dict:
    """Execute a single tool_use block + format as tool_result."""
    name = block.name
    args = block.input
    try:
        result = await TOOL_FUNCS[name](**args)
        return {"type": "tool_result", "tool_use_id": block.id, "content": json.dumps(result)}
    except Exception as e:
        return {"type": "tool_result", "tool_use_id": block.id, "content": f"ERROR: {e}", "is_error": True}


async def agent_loop(user_msg: str, max_iter: int = 5) -> str:
    client = AsyncAnthropic()
    messages = [{"role": "user", "content": user_msg}]

    for i in range(max_iter):
        resp = await client.messages.create(
            model="claude-sonnet-4-5",
            max_tokens=1024,
            tools=TOOLS,
            messages=messages,
        )
        # Append the assistant turn (contains the tool_use blocks)
        messages.append({"role": "assistant", "content": resp.content})

        if resp.stop_reason == "end_turn":
            return "".join(b.text for b in resp.content if b.type == "text")

        if resp.stop_reason == "tool_use":
            # PARALLEL execution of all tool_use blocks in this turn
            tool_blocks = [b for b in resp.content if b.type == "tool_use"]
            results = await asyncio.gather(*[execute_tool(b) for b in tool_blocks])
            # Single user turn with all results
            messages.append({"role": "user", "content": results})
            continue

        return f"unexpected stop_reason={resp.stop_reason}"
    return "max iterations reached"


if __name__ == "__main__":
    out = asyncio.run(agent_loop("What's the weather AND time in Tokyo and Paris?"))
    print(out)

