// src/index.ts -- Cloudflare Worker streaming Llama 3.1 8B
//
// wrangler.toml:
//   name = "ossai-edge"
//   main = "src/index.ts"
//   compatibility_date = "2024-11-01"
//   [ai]
//   binding = "AI"
//
// deploy: npx wrangler deploy

export interface Env {
  AI: any;  // Cloudflare AI binding (type from @cloudflare/workers-types)
}

export default {
  async fetch(request: Request, env: Env): Promise<Response> {
    const url = new URL(request.url);
    if (url.pathname !== "/chat" || request.method !== "POST") {
      return new Response("POST /chat", { status: 404 });
    }
    const { prompt, stream = true } = await request.json<{ prompt: string; stream?: boolean }>();
    if (!prompt) return new Response("missing prompt", { status: 400 });

    const aiArgs = {
      messages: [{ role: "user", content: prompt }],
      stream,
      max_tokens: 500,
      temperature: 0.4,
    };

    if (!stream) {
      const result = await env.AI.run("@cf/meta/llama-3.1-8b-instruct", aiArgs);
      return new Response(JSON.stringify(result), { headers: { "Content-Type": "application/json" } });
    }

    // Streamed: returns a ReadableStream of SSE events
    const aiStream = await env.AI.run("@cf/meta/llama-3.1-8b-instruct", aiArgs);
    return new Response(aiStream, {
      headers: {
        "Content-Type": "text/event-stream",
        "Cache-Control": "no-cache",
        "Connection": "keep-alive",
      },
    });
  },
} satisfies ExportedHandler<Env>;

