export class BedrockStack extends Stack {
  constructor(scope: Construct, id: string, props?: StackProps) {
    super(scope, id, props);

    const key = new kms.Key(this, 'PromptCacheKey', { enableKeyRotation: true });

    const fn = new lambda.Function(this, 'BedrockInvoke', {
      runtime: lambda.Runtime.PYTHON_3_12,
      handler: 'index.handler',
      code: lambda.Code.fromAsset('./src'),
      environment: { CACHE_KMS_KEY_ID: key.keyId },
    });
    fn.addToRolePolicy(new iam.PolicyStatement({
      actions: ['bedrock:InvokeModel'],
      resources: ['arn:aws:bedrock:us-east-1::foundation-model/anthropic.claude-sonnet-4-5'],
    }));
  }
}
